const express = require('express');
const axios = require('axios');
const path = require('path');
require('dotenv').config();

const app = express();
const port = 3000;

app.use(express.json());
app.use(express.static('public'));

app.post('/api/verify-phone', async (req, res) => {
    const { phoneNumber } = req.body;

    if (!phoneNumber) {
        return res.status(400).json({ error: 'Phone number is required' });
    }

    const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;
    const PREMBLY_APP_ID = process.env.PREMBLY_APP_ID;

    try {
        const response = await axios.post('https://api.prembly.com/verification/phone', {
            number: phoneNumber
        }, {
            headers: {
                'x-api-key': PREMBLY_API_KEY,
                'app-id': PREMBLY_APP_ID,
                'Content-Type': 'application/json'
            }
        });

        res.json(response.data);
    } catch (error) {
        console.error('Prembly API Error:', error.response ? error.response.data : error.message);
        res.status(error.response ? error.response.status : 500).json({
            error: 'Failed to verify phone number',
            details: error.response ? error.response.data : error.message
        });
    }
});

app.listen(port, () => {
    console.log(`Server running at http://localhost:${port}`);
});

